package contrib.analyzers.src.org.apache.lucene.analysis.miscellaneous;

public class PrefixAndSuffixAwareTokenFilter extends TokenStream { private PrefixAwareTokenFilter suffix ; public PrefixAndSuffixAwareTokenFilter ( TokenStream prefix , TokenStream input , TokenStream suffix ) { prefix = new PrefixAwareTokenFilter ( prefix , input ) { public Token updateSuffixToken ( Token suffixToken , Token lastInputToken ) { return PrefixAndSuffixAwareTokenFilter . this . updateInputToken ( suffixToken , lastInputToken ) ; } } ; this . suffix = new PrefixAwareTokenFilter ( prefix , suffix ) { public Token updateSuffixToken ( Token suffixToken , Token lastInputToken ) { return PrefixAndSuffixAwareTokenFilter . this . updateSuffixToken ( suffixToken , lastInputToken ) ; } } ; } public Token updateInputToken ( Token inputToken , Token lastPrefixToken ) { inputToken . setStartOffset ( lastPrefixToken . endOffset ( ) + inputToken . startOffset ( ) ) ; inputToken . setEndOffset ( lastPrefixToken . endOffset ( ) + inputToken . endOffset ( ) ) ; return inputToken ; } public Token updateSuffixToken ( Token suffixToken , Token lastInputToken ) { suffixToken . setStartOffset ( lastInputToken . endOffset ( ) + suffixToken . startOffset ( ) ) ; suffixToken . setEndOffset ( lastInputToken . endOffset ( ) + suffixToken . endOffset ( ) ) ; return suffixToken ; } public Token next ( final Token reusableToken ) throws IOException { assert reusableToken != null ; return suffix . next ( reusableToken ) ; } public void reset ( ) throws IOException { suffix . reset ( ) ; } public void close ( ) throws IOException { suffix . close ( ) ; } }